import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a string to handle both real newlines and escaped "\\n" sequences
        String data = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        data = data.replace("\\n", "\n"); // convert escaped newlines to real newlines
        Scanner sc = new Scanner(data);
        StringBuilder sb = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            long ans = 0L;
            int[] cnt = new int[3];
            int r = 0;
            for (int l = 0; l < n; l++) {
                while (r < n && (cnt[0] == 0 || cnt[1] == 0 || cnt[2] == 0)) {
                    cnt[a[r]]++;
                    r++;
                }
                if (cnt[0] > 0 && cnt[1] > 0 && cnt[2] > 0) {
                    ans += n - r + 1;
                }
                cnt[a[l]]--;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

